import{c as e,O as a,i,m as n}from"./chunks/framework.BWIk71Uc.js";const g=JSON.parse('{"title":"Understanding the Overall Microservices Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/spring/spring-cloud-alibaba/microservice-architecture.md","filePath":"en/notes/spring/spring-cloud-alibaba/microservice-architecture.md","lastUpdated":1779889127000}'),t={name:"en/notes/spring/spring-cloud-alibaba/microservice-architecture.md"};function l(p,s,r,c,h,o){return a(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1779889127000"},[...s[0]||(s[0]=[n(`<h1 id="understanding-the-overall-microservices-architecture" tabindex="-1">Understanding the Overall Microservices Architecture <a class="header-anchor" href="#understanding-the-overall-microservices-architecture" aria-label="Permalink to “Understanding the Overall Microservices Architecture”">​</a></h1><h2 id="_1-1-problems-with-monolithic-architecture" tabindex="-1">1.1 Problems with Monolithic Architecture <a class="header-anchor" href="#_1-1-problems-with-monolithic-architecture" aria-label="Permalink to “1.1 Problems with Monolithic Architecture”">​</a></h2><p>Traditional monolithic applications typically bundle all functionalities into a single project:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>User Module</span></span>
<span class="line"><span>Order Module</span></span>
<span class="line"><span>Inventory Module</span></span>
<span class="line"><span>Payment Module</span></span>
<span class="line"><span>Marketing Module</span></span>
<span class="line"><span>Admin Management Module</span></span></code></pre></div><p>These modules are ultimately packaged into a single application, for example:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mall-system.jar</span></span></code></pre></div><p>The advantages of monolithic architecture are:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Simple Development</span></span>
<span class="line"><span>Simple Deployment</span></span>
<span class="line"><span>Simple Invocation</span></span>
<span class="line"><span>Suitable for Small Projects</span></span></code></pre></div><p>However, as business complexity grows, problems become increasingly apparent:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. Codebase becomes too large, making maintenance difficult.</span></span>
<span class="line"><span>2. Tight coupling between modules.</span></span>
<span class="line"><span>3. A problem in one module can affect the entire system.</span></span>
<span class="line"><span>4. Unable to scale individual modules independently.</span></span>
<span class="line"><span>5. Multiple teams working together can easily interfere with each other.</span></span>
<span class="line"><span>6. Deploying a change requires redeploying the entire system.</span></span></code></pre></div><hr><h2 id="_1-2-what-is-microservices-architecture" tabindex="-1">1.2 What is Microservices Architecture? <a class="header-anchor" href="#_1-2-what-is-microservices-architecture" aria-label="Permalink to “1.2 What is Microservices Architecture?”">​</a></h2><p>Microservices architecture breaks down a large system into multiple small services.</p><p>For example, an e-commerce system can be split into:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>User Service: user-service</span></span>
<span class="line"><span>Order Service: order-service</span></span>
<span class="line"><span>Inventory Service: stock-service</span></span>
<span class="line"><span>Payment Service: payment-service</span></span>
<span class="line"><span>Gateway Service: gateway-service</span></span></code></pre></div><p>Each service is an independent Spring Boot application.</p><p>They communicate with each other via HTTP, RPC, message queues, etc.</p><p>Typical structure:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>User Request</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Spring Cloud Gateway</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>order-service</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>stock-service</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>payment-service</span></span></code></pre></div><hr><h2 id="_1-3-new-problems-introduced-by-microservices" tabindex="-1">1.3 New Problems Introduced by Microservices <a class="header-anchor" href="#_1-3-new-problems-introduced-by-microservices" aria-label="Permalink to “1.3 New Problems Introduced by Microservices”">​</a></h2><p>After splitting into microservices, new technical challenges arise.</p><h3 id="_1-3-1-how-to-manage-service-addresses" tabindex="-1">1.3.1 How to Manage Service Addresses? <a class="header-anchor" href="#_1-3-1-how-to-manage-service-addresses" aria-label="Permalink to “1.3.1 How to Manage Service Addresses?”">​</a></h3><p>Previously, a monolithic project had only one address:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>localhost:8080</span></span></code></pre></div><p>With microservices, there can be many addresses:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user-service    192.168.1.11:8081</span></span>
<span class="line"><span>order-service   192.168.1.12:8082</span></span>
<span class="line"><span>stock-service   192.168.1.13:8083</span></span>
<span class="line"><span>payment-service 192.168.1.14:8084</span></span></code></pre></div><p>Moreover, services may need to scale:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>order-service 192.168.1.12:8082</span></span>
<span class="line"><span>order-service 192.168.1.15:8082</span></span>
<span class="line"><span>order-service 192.168.1.16:8082</span></span></code></pre></div><p>Therefore, a service registry is needed.</p><p>In Spring Cloud Alibaba, the typical choice is:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Nacos Discovery</span></span></code></pre></div><hr><h3 id="_1-3-2-how-to-manage-configuration-centrally" tabindex="-1">1.3.2 How to Manage Configuration Centrally? <a class="header-anchor" href="#_1-3-2-how-to-manage-configuration-centrally" aria-label="Permalink to “1.3.2 How to Manage Configuration Centrally?”">​</a></h3><p>Each service has its own configuration:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Port</span></span>
<span class="line"><span>Database Address</span></span>
<span class="line"><span>Redis Address</span></span>
<span class="line"><span>Feature Toggles</span></span>
<span class="line"><span>Business Parameters</span></span>
<span class="line"><span>Rate Limiting Rules</span></span>
<span class="line"><span>Log Level</span></span></code></pre></div><p>If configurations are scattered locally across each service, making changes becomes cumbersome.</p><p>Therefore, a configuration center is needed.</p><p>In Spring Cloud Alibaba, the typical choice is:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Nacos Config</span></span></code></pre></div><hr><h3 id="_1-3-3-how-do-services-call-each-other" tabindex="-1">1.3.3 How Do Services Call Each Other? <a class="header-anchor" href="#_1-3-3-how-do-services-call-each-other" aria-label="Permalink to “1.3.3 How Do Services Call Each Other?”">​</a></h3><p>If the order service needs to call the inventory service, using RestTemplate directly can be cumbersome:</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">restTemplate.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getForObject</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://stock-service/stock/reduce&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, String.class);</span></span></code></pre></div><p>A more elegant approach is to declare an interface and let Spring generate the remote call proxy for us.</p><p>In Spring Cloud, the typical choice is:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>OpenFeign</span></span></code></pre></div><hr><h3 id="_1-3-4-what-if-an-interface-receives-excessive-traffic" tabindex="-1">1.3.4 What If an Interface Receives Excessive Traffic? <a class="header-anchor" href="#_1-3-4-what-if-an-interface-receives-excessive-traffic" aria-label="Permalink to “1.3.4 What If an Interface Receives Excessive Traffic?”">​</a></h3><p>If a particular interface suddenly receives a large number of requests, the service might crash.</p><p>A rate limiting component is needed to protect the service.</p><p>In Spring Cloud Alibaba, the typical choice is:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Sentinel</span></span></code></pre></div><hr><h3 id="_1-3-5-what-if-a-downstream-service-fails" tabindex="-1">1.3.5 What If a Downstream Service Fails? <a class="header-anchor" href="#_1-3-5-what-if-a-downstream-service-fails" aria-label="Permalink to “1.3.5 What If a Downstream Service Fails?”">​</a></h3><p>For example, if the order service calls the inventory service and the inventory service fails, the order service should not hang indefinitely.</p><p>A circuit breaker and fallback mechanism is needed:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Too many downstream exceptions</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Temporarily open the circuit</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Fail fast or return fallback data</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Attempt recovery after a period</span></span></code></pre></div><p>In Spring Cloud Alibaba, the typical choice is also:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Sentinel</span></span></code></pre></div><hr><h3 id="_1-3-6-how-does-the-frontend-access-multiple-services" tabindex="-1">1.3.6 How Does the Frontend Access Multiple Services? <a class="header-anchor" href="#_1-3-6-how-does-the-frontend-access-multiple-services" aria-label="Permalink to “1.3.6 How Does the Frontend Access Multiple Services?”">​</a></h3><p>The frontend should not directly access many microservices:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http://user-service/user/info</span></span>
<span class="line"><span>http://order-service/order/list</span></span>
<span class="line"><span>http://stock-service/stock/list</span></span></code></pre></div><p>Typically, it accesses a unified gateway:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http://gateway-service/api/user/info</span></span>
<span class="line"><span>http://gateway-service/api/order/list</span></span>
<span class="line"><span>http://gateway-service/api/stock/list</span></span></code></pre></div><p>The gateway is responsible for:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Unified Entry Point</span></span>
<span class="line"><span>Unified Authentication</span></span>
<span class="line"><span>Unified CORS Handling</span></span>
<span class="line"><span>Unified Logging</span></span>
<span class="line"><span>Unified Routing</span></span>
<span class="line"><span>Unified Rate Limiting</span></span>
<span class="line"><span>Unified Context Propagation</span></span></code></pre></div><p>In Spring Cloud, the typical choice is:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Spring Cloud Gateway</span></span></code></pre></div><hr><h2 id="_1-4-final-practical-architecture-for-this-guide" tabindex="-1">1.4 Final Practical Architecture for This Guide <a class="header-anchor" href="#_1-4-final-practical-architecture-for-this-guide" aria-label="Permalink to “1.4 Final Practical Architecture for This Guide”">​</a></h2><p>We will ultimately build the following services:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>nacos-server</span></span>
<span class="line"><span>sentinel-dashboard</span></span>
<span class="line"><span></span></span>
<span class="line"><span>gateway-service      Gateway Service, Port 9000</span></span>
<span class="line"><span>order-service        Order Service, Port 8081</span></span>
<span class="line"><span>stock-service        Inventory Service, Port 8082</span></span></code></pre></div><p>Call chain:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Browser / Postman</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>gateway-service</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>order-service</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>OpenFeign</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>stock-service</span></span></code></pre></div><p>Context propagation chain:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Request Header X-Request-Id</span></span>
<span class="line"><span>Request Header X-User-Id</span></span>
<span class="line"><span>Request Header X-Tenant-Id</span></span>
<span class="line"><span></span></span>
<span class="line"><span>gateway-service</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>order-service Controller</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>order-service Feign RequestInterceptor</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>stock-service Controller</span></span></code></pre></div>`,78)])])}const k=e(t,[["render",l]]);export{g as __pageData,k as default};
